css:
@import url("https://fontsapi.zeoseven.com/40/main/result.css");

/* ==================== 深海鲸歌主题 ==================== */
/* 主色：#F0F8FF 浅海蓝 | 强调 #0A2D3C | 字体 #05202c */

/* === 字体设置=== */
@font-face {
    font-family: 'ZhuqueFangsong';
    src: url("http://sharkpan.xyz/f/24j6iQ/%E4%B8%AD%E6%96%87%20-%20Huiwen.otf") format('truetype');
    font-weight: 200;
    font-style: normal;
}
@font-face {
  font-family: 'Huiwen';
  src: url("http://sharkpan.xyz/f/24j6iQ/%E4%B8%AD%E6%96%87%20-%20Huiwen.otf") format('opentype');
  font-weight: 400;
  font-style: normal;
}

body {
    font-family: 'ZhuqueFangsong', serif;
    font-weight: normal;
    line-height: 1.5;
    background: linear-gradient(160deg, #E0F0F7 0%, #D1E6F3 100%);
    color: #05202c;
}

/* === 头像容器装饰 === */
.mes .avatar {
    cursor: pointer;
    position: absolute;
    top: -105px;
    left: 12%;
    transform: translateX(-50%);
    width: 80px;
    height: 80px;
    object-fit: cover;
    border-radius: 60%;
    overflow: visible;
    z-index: -1;
    /* 海洋风格边框 */
    border: 1.5px solid #0A2D3C;
    box-shadow: 0 0 8px rgba(136, 193, 217, 0.5);
}

/* 添加贴图装饰*/
.mes .avatar::after {
    content: "";
    position: absolute;
    width: 395px; 
    height: 395px;
    background-image: url('https://i.postimg.cc/K8LsyWm9/image.png'); /* 指定头像URL */
    background-size: contain;
    background-repeat: no-repeat;
    top: -39px;
    right: -285px;
    z-index: 111;
}

/* === 消息容器样式 === */
.mes_text q {
    /* 海洋风格虚线边框 */
    border: 2px dashed #88C1D9;  
    border-radius: 8px;          
    padding: 2px 5px;
    position: relative;
    background-color: #F0F8FF;   
    display: inline-block;
    margin: 5px;

    /* 海洋色荧光笔效果 */
    background-image: linear-gradient(to right, 
        rgba(136, 193, 217, 0.3) 0%,  
        rgba(136, 193, 217, 0.3) 100%);
    background-repeat: no-repeat;
    background-size: 100% 50%;
    background-position: 0 60%;
}

/* 添加🐋海洋主题装饰 */
.mes_text q::before {
    content: "🐋";
    position: absolute;
    left: -10px;
    font-size: 18px;
}

.mes_text q::after {
    content: "🐋";
    position: absolute;
    right: -10px;
    font-size: 18px;
}

@media screen and (max-width: 1000px) {
    *::-webkit-scrollbar {
        display: none;
    }

    .mesIDDisplay {
      position: absolute !important;
      top: -73px!important;
      right: 110px;
      z-index: 10;
    }

    .mes {
        width: 95%;
        max-width: 560px;
        margin: 200px auto 10px;
        padding: 8px;
        margin-bottom: 15px !important;
        border-radius: 40px !important;
        position: relative !important;
        padding-top: 15px !important;
        z-index: 1;

        /* 海洋风格虚线边框 */
        border: 3px dotted #88C1D9 !important;

        /* 海洋风格格子背景 */
        background-color: #E0F0F7 !important;
        background-image: 
            linear-gradient(#c5e3f0 1px, transparent 1px),
            linear-gradient(90deg, #c5e3f0 1px, transparent 1px);
        background-size: 10px 10px;
        background-position: -1px -1px;

        /* 海洋风格内阴影 */
        box-shadow: inset 0 0 8px rgba(10, 45, 60, 0.2);
    }

    .mes::after {
        content: "";
        position: absolute;
        background: url('https://i.postimg.cc/BvBYj1LH/image.png') no-repeat; /* 指定聊天背景URL */
        background-size: contain;
        width:410px;
        height: 380px;
        bottom: -288px;
        left: -35px;
        z-index: -1;
        transform: rotate(0deg);
    }

    .mes {
      position: relative;
    }

    .mes_timer {
      position: absolute !important;
      top: -73px!important;
      right: 55px;
      z-index: 11;
    }

    .name_text {
      position: absolute;
      top: -70px;
      left: 140px;
      font-size: 11px;
      z-index: 11;  
    }

    .mes_text {
        margin-left: 0;
        margin-right: 6px;
        padding-left: 0;
        padding-right: 0;
    }

    .mes .avatar img {
        width: 67px !important;
        height: 67px !important;
        display: block; 
    }

    .mes_text {
      line-height: 1.3;
      letter-spacing: 1px;
      word-spacing: 2px;
    }
}

/* === 输入框和按钮样式 === */
.options-content,
#send_form,
#char-management-dropdown,
.buttons_block .menu_button,
#tagInput,
.menu_button,
#form_create textarea,
#persona_search_bar,
#user-settings-block h4,
.textarea_compact,
.drawer-content select,
.neo-range-input,
#extensions_settings .inline-drawer-toggle.inline-drawer-header,
#extensions_settings2 .inline-drawer-toggle.inline-drawer-header,
.standoutHeader,
.text_pole,
.range-block-counter input {
    /* 海洋风格凹槽边框 */
    border: 2px groove #88C1D9;
    border-radius: 8px !important;
    padding: 8px 12px;

    /* 海洋风格格子背景 */
    background-color: #E0F0F7;
    background-image: 
        linear-gradient(#c5e3f0 1px, transparent 1px),
        linear-gradient(90deg, #c5e3f0 1px, transparent 1px);
    background-size: 15px 15px;

    box-shadow: none !important;
    image-rendering: auto;
}

/* 文本框占位符样式 */
#send_textarea:placeholder-shown {
    border: 2px groove #88C1D9;
    background-color: #E0F0F7;
    background-image: 
        linear-gradient(#c5e3f0 1px, transparent 1px),
        linear-gradient(90deg, #c5e3f0 1px, transparent 1px);
    background-size: 15px 15px;   
}

/* 设置面板的内凹效果 */
.userSettingsInnerExpandable {
    border: 2px groove #88C1D9;
    background-color: #E0F0F7;
    background-image: 
        linear-gradient(#c5e3f0 1px, transparent 1px),
        linear-gradient(90deg, #c5e3f0 1px, transparent 1px);
    background-size: 15px 15px;
    padding: 12px;
    border-radius: 8px;
    box-shadow: none;
}

/* 主文本框样式 */
#send_textarea {
    border: 2px groove #88C1D9;
    border-radius: 8px;
    background-color: #E0F0F7;
    background-image: 
        linear-gradient(#c5e3f0 1px, transparent 1px),
        linear-gradient(90deg, #c5e3f0 1px, transparent 1px);
    background-size: 15px 15px;
    padding: 12px;
    font-family: 'Huiwen', 'ZhuqueFangsong', serif !important;
    font-size: 16px !important;
    font-weight: 400 !important;
    line-height: 1.6 !important;
    color: #0A2D3C !important;
}

/* 消息文本字体设置 */
.mes_text {
    font-family: 'ZhuqueFangsong', serif !important;
    font-weight: 300 !important;
}

/* 占位符状态特殊样式 */
#send_textarea:placeholder-shown {
    margin-top: -5px;
    background-image: none;
    background-color: #d1e6f3;
    color: #3a7c9e;
    border-style: dashed;
}

/* === 代码块样式 === */
pre, code {
    border: 2px solid #88C1D9;
    background-color: #F0F8FF;
    border-radius: 5px;
    box-shadow: 3px 3px 0 #1D5D7A;
    padding: 4px 6px;
    font-family: 'Courier New', monospace;
    overflow-x: auto;
}

pre {
    padding: 1px 3px;
    line-height: 1.4;
    margin: 15px 0;
}

pre, code {
    color: #0A2D3C;
}

/* === 海洋思维链头部容器=== */
.mes_reasoning_header {
  background: linear-gradient(135deg, #0A2D3C 0%, #1D5D7A 100%);
  border: 1.5px solid #88C1D9;
  border-radius: 10px;
  padding: 8px 26px;
  margin: 14px auto;
  color: #F0F8FF;
  box-shadow: 0 4px 16px rgba(10,45,60,0.15);
  display: flex;
  align-items: center;
  justify-content: center;
  backdrop-filter: blur(7px);
  position: relative;
  max-width: 92%;
  width: fit-content;
}

/* 🐋 emoji作为左右角标 */
.mes_reasoning_header_title::before,
.mes_reasoning_header_title::after {
  content: "🐋";
  display: inline-block;
  margin: 0 5px;
  opacity: 0.75;
  filter: drop-shadow(0 0 2px rgba(136, 193, 217, 0.5));
}

/* 标题文字 */
.mes_reasoning_header_title {
  font-size: 13px;
  font-weight: bold;
  color: #F0F8FF;
  padding: 0 14px;
  white-space: nowrap;
  overflow: visible;
  text-overflow: unset;
  text-align: center;
  letter-spacing: 0.04em;
  text-shadow: 0 1px 6px rgba(10,45,60,0.2), 0 0.5px 2px rgba(240,248,255,0.2);
}

/* 箭头样式 */
.mes_reasoning_arrow {
  font-size: 13px;
  color: #88C1D9;
  cursor: pointer;
  transition: transform 0.3s ease, color 0.3s ease;
  margin-left: 10px;
  margin-right: 4px;
  vertical-align: middle;
}
.mes_reasoning_arrow:hover {
  color: #F0F8FF;
  background: #0A2D3C;
  transform: scale(1.17);
}
